for $r in sql(' SELECT est.oi_estudio_cv, est.d_otro_est_educ, est.c_estado, est.oi_nivel_estudio, est.oi_area_est, est.d_nom_carrera, est.d_institucion, est.e_dur_carrera, est.oi_unidad_tiempo, est.d_localidad, est.e_ano_inicio, est.e_ano_fin, est.e_ano_curso, est.e_ult_ano_cursado, est.oi_estudio,
niv.d_nivel_estudio, area.d_area_est, ut.d_unidad_tiempo, es.d_estudio
FROM SDP01_ESTUDIOS_CV as est, PER12_NIVELES_EST as niv, ORG43_AREAS_EST as area, ORG11_ESTUDIOS as es, ORG25_UNIDADES_TPO as ut
JOIN est.oi_nivel_estudio INNER niv.oi_nivel_estudio, est.oi_area_est LEFT OUTER area.oi_area_est, est.oi_estudio LEFT OUTER es.oi_estudio, est.oi_unidad_tiempo LEFT OUTER ut.oi_unidad_tiempo
WHERE est.oi_cv = {#SOURCE:@oi_cv}
')/ROWS/ROW

